import { useMemo } from 'react';
import { motion, type Variants } from 'framer-motion';

/**
 * RoboVITics logo-assembly animation.
 *
 * The source SVG is a halftone-style render of the wordmark made of ~900+
 * tiny <path>/<g> fragments. Animating every single fragment as its own
 * Framer Motion node would tank performance (especially on mobile), so the
 * fragments have been pre-clustered (offline, by spatial position) into 28
 * "pieces". Each piece's internal markup is 100% untouched/original SVG —
 * nothing was re-vectorized or redrawn. Pieces are just grouped so we can
 * animate a manageable number of independently-moving chunks instead of
 * ~900 individual nodes.
 */

interface AssemblyPiece {
    id: string;
    /** Starting horizontal offset (px, in the 4096-wide viewBox space) */
    offsetX: number;
    /** Starting vertical offset (px, in the 683-tall viewBox space) */
    offsetY: number;
    /** Starting rotation (deg) */
    rotation: number;
    /** Starting scale */
    scale: number;
    /** Rough "size" of this piece (path count) — used to vary spring weight */
    weight: number;
    /** Stagger delay (s) */
    delay: number;
    /** Raw, untouched SVG markup for this piece's paths */
    markup: string;
}


