interface LogoAssemblyProps {
    /** Called once the assembly + glow + lock-in sequence has fully finished. */
    onComplete?: () => void;
    className?: string;
}

const VIEW_W = 4096;
const VIEW_H = 683;

export default function LogoAssembly({ onComplete, className }: LogoAssemblyProps) {
    const pieces = ASSEMBLY_PIECES as AssemblyPiece[];

    const maxDelay = useMemo(
        () => pieces.reduce((max, p) => Math.max(max, p.delay), 0),
        [pieces]
    );

    // Each piece's own travel time. Kept short + consistent across pieces so
    // the whole thing reads as one cohesive glide rather than separate
    // mini-animations finishing at different speeds.
    const travelDuration = 0.78;
    const assemblyEnd = maxDelay + travelDuration;
    // Quick settle-in jiggle (a little wobble once every piece has landed),
    // played right before the lock-in glow pulse.
    const jiggleDuration = 0.35;
    const lockInDuration = 0.55;
    const postAssemblyTotal = jiggleDuration + lockInDuration;
    const jiggleEndFrac = jiggleDuration / postAssemblyTotal;

    const pieceVariants: Variants = {
        hidden: ({ offsetX, offsetY, rotation, scale }: AssemblyPiece) => ({
            x: offsetX,
            y: offsetY,
            rotate: rotation,
            scale,
            opacity: 0,
        }),
        visible: ({ weight, delay }: AssemblyPiece) => {
            // Critically-damped-ish springs: damping scales with stiffness so
            // pieces glide to rest with little to no overshoot/wobble. Heavier
            // pieces (more original path fragments) are just slightly slower
            // and "weightier", not bouncier.
            const stiffness = 95 - Math.min(weight, 40) * 0.6; // 95 -> ~71
            const damping = stiffness * 0.92; // near-critical damping, smooth glide
            return {
                x: 0,
                y: 0,
                rotate: 0,
                scale: 1,
                opacity: 1,
                transition: {
                    delay,
                    type: 'spring',
                    stiffness,
                    damping,
                    mass: 0.6 + weight / 90,
                    opacity: { delay, duration: travelDuration * 0.7, ease: 'easeOut' },
                },
            };
        },
    };

    return (
        <motion.div
            className={className}
            initial="hidden"
            animate="visible"
            style={{ position: 'relative', width: '100%' }}
        >
            <motion.svg
                viewBox={`0 0 ${VIEW_W} ${VIEW_H}`}
                width="100%"
                height="auto"
                xmlns="http://www.w3.org/2000/svg"
                style={{ display: 'block', overflow: 'visible' }}
                // Settle-in jiggle (rotate wobble) immediately after assembly,
                // then the precision lock-in: scale 1 -> 1.018 -> 1 + soft glow
                // pulse, all in one continuous, smoothly-eased timeline.
                initial={{ scale: 1, rotate: 0, filter: 'drop-shadow(0 0 0px rgba(120,200,255,0))' }}
                animate={{
                    rotate: [0, -2, 2.2, -1.1, 0.5, 0, 0],
                    scale: [1, 1, 1, 1, 1, 1.018, 1],
                    filter: [
                        'drop-shadow(0 0 0px rgba(150,210,255,0))',
                        'drop-shadow(0 0 0px rgba(150,210,255,0))',
                        'drop-shadow(0 0 0px rgba(150,210,255,0))',
                        'drop-shadow(0 0 0px rgba(150,210,255,0))',
                        'drop-shadow(0 0 0px rgba(150,210,255,0))',
                        'drop-shadow(0 0 16px rgba(150,210,255,0.7))',
                        'drop-shadow(0 0 4px rgba(150,210,255,0.2))',
                    ],
                }}
                transition={{
                    duration: postAssemblyTotal,
                    delay: assemblyEnd,
                    times: [0, 0.18, 0.36, 0.54, jiggleEndFrac, jiggleEndFrac + (1 - jiggleEndFrac) * 0.65, 1],
                    ease: 'easeInOut',
                }}
                onAnimationComplete={() => onComplete?.()}
            >
                {pieces.map((piece) => (
                    <motion.g
                        key={piece.id}
                        custom={piece}
                        variants={pieceVariants}
                        style={{ transformOrigin: '50% 50%', willChange: 'transform, opacity' }}
                        dangerouslySetInnerHTML={{ __html: piece.markup }}
                    />
                ))}
            </motion.svg>
        </motion.div>
    );
}

export function getAssemblyDurationMs(): number {
    const pieces = ASSEMBLY_PIECES as AssemblyPiece[];
    const maxDelay = pieces.reduce((max, p) => Math.max(max, p.delay), 0);
    const travelDuration = 0.78;
    const assemblyEnd = maxDelay + travelDuration;
    const jiggleDuration = 0.35;
    const lockInDuration = 0.55;
    const settleBuffer = 0.4; // matches the requested pause before typing starts
    return (assemblyEnd + jiggleDuration + lockInDuration + settleBuffer) * 1000;
}